import{_ as a,o as r,c as l,ag as i}from"./chunks/framework.BPmc_f4o.js";const h=JSON.parse('{"title":"Global Security","description":"","frontmatter":{},"headers":[],"relativePath":"global-security/global-security.md","filePath":"global-security/global-security.md"}'),o={name:"global-security/global-security.md"};function t(s,e,n,d,c,g){return r(),l("div",null,[...e[0]||(e[0]=[i('<p><span style="display:inline-block;padding:1px 8px;border-radius:3px;background:#2e7d32;color:#fff;font-size:11px;font-weight:600;">FREE</span> <span style="display:inline-block;padding:1px 8px;border-radius:3px;background:#1565c0;color:#fff;font-size:11px;font-weight:600;">PRO</span></p><h1 id="global-security" tabindex="-1">Global Security <a class="header-anchor" href="#global-security" aria-label="Permalink to &quot;Global Security&quot;">​</a></h1><p>Global Security centralizes WordPress hardening toggles used by headless and API-first deployments. These controls are installation-wide and help reduce attack surface before route-level rules are evaluated.</p><hr><h2 id="core-security-toggles" tabindex="-1">Core Security Toggles <a class="header-anchor" href="#core-security-toggles" aria-label="Permalink to &quot;Core Security Toggles&quot;">​</a></h2><ul><li><strong>Disable XML-RPC</strong>: blocks legacy XML-RPC entry points.</li><li><strong>Disable comments and pingbacks</strong>: reduces spam and legacy abuse vectors.</li><li><strong>Disable feeds/sitemaps where needed</strong>: limits passive discovery channels.</li><li><strong>Disable theme editor</strong>: prevents direct file edits from admin UI.</li></ul><hr><h2 id="header-and-surface-hardening" tabindex="-1">Header and Surface Hardening <a class="header-anchor" href="#header-and-surface-hardening" aria-label="Permalink to &quot;Header and Surface Hardening&quot;">​</a></h2><ul><li><strong>Security headers</strong>: enables common hardening headers through a guided toggle.</li><li><strong>CORS-related guardrails</strong>: keeps API surface aligned with explicit access policy.</li><li><strong>Hide server signatures where possible</strong>: reduces exposed fingerprinting hints.</li></ul><hr><h2 id="file-and-platform-hardening" tabindex="-1">File and Platform Hardening <a class="header-anchor" href="#file-and-platform-hardening" aria-label="Permalink to &quot;File and Platform Hardening&quot;">​</a></h2><ul><li><strong>Uploads directory protections</strong>: applies safer execution posture for uploads.</li><li><strong>Configuration permissions checks</strong>: validates critical file permissions.</li></ul><hr><h2 id="recommended-rollout" tabindex="-1">Recommended Rollout <a class="header-anchor" href="#recommended-rollout" aria-label="Permalink to &quot;Recommended Rollout&quot;">​</a></h2><ol><li>Enable XML-RPC disable.</li><li>Enable comments/pingbacks disable if your site does not need them.</li><li>Enable security headers and verify front-end behavior.</li><li>Enable file protections.</li><li>Re-test login, media upload, and API routes.</li></ol><hr><h2 id="related-modules" tabindex="-1">Related Modules <a class="header-anchor" href="#related-modules" aria-label="Permalink to &quot;Related Modules&quot;">​</a></h2><ul><li>For login attack mitigation, see <a href="/login-hardening/login-hardening.html">Auth Hardening</a>.</li><li>For API ingress restrictions, see <a href="/global-ip-filtering/global-ip-filtering.html">Global IP Filtering</a>.</li><li>For Pro-only headless lockout controls, see <a href="/wordpress-mode/wordpress-mode.html">WordPress Mode</a>.</li></ul>',18)])])}const p=a(o,[["render",t]]);export{h as __pageData,p as default};
